#include <stdio.h>

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int N; scanf("%d", &N);
        long long sumId = 0, sumChildren = 0;
        for (int i = 0; i < N; ++i) {
            int id, childSum; scanf("%d %d", &id, &childSum);
            sumId += id;
            sumChildren += childSum;
        }
        long long root = sumId - sumChildren;
        printf("%lld\n", root);
    }
    return 0;
}

